// CONSULTAR API ALERTAS v2.0
// Credenciales hardcodeadas — compatible con n8n free plan.
const ALERTAS_TOKEN = 'REEMPLAZAR_CON_TU_TOKEN'; // genera con: openssl rand -base64 32
const API_URL       = 'https://deudas.sekaitech.com.pe';

let result;
try {
  result = await this.helpers.httpRequest({
    method: 'GET',
    url: API_URL + '/api/alertas/vencimientos?dias=7',
    headers: {
      'X-Alertas-Token': ALERTAS_TOKEN,
      'Accept': 'application/json'
    },
    timeout: 20000
  });
} catch(e) {
  return [{ json: { error: true, message: e.message } }];
}

return [{ json: result }];

