// =================================================================
//  PROCESAR DATOS Y PREPARAR MENSAJES
//  Genera hasta 3 mensajes separados:
//    1. Header resumen   2. Bloque deudas   3. Bloque ordenes
// =================================================================
const data = $input.first().json;

const deudas  = Array.isArray(data.deudas)  ? data.deudas  : [];
const ordenes = Array.isArray(data.ordenes) ? data.ordenes : [];

if (deudas.length === 0 && ordenes.length === 0) {
  return [{ json: { hayAlertas: false, mensajes: [], total: 0 } }];
}

const urgIcon = (d) => {
  if (d <= 0) return '🔴';  // red circle
  if (d <= 3) return '🟠';  // orange circle
  return '🟡';              // yellow circle
};

const labelDias = (d) => {
  if (d < 0)   return '⚠️ VENCIDO hace ' + Math.abs(d) + ' dia(s)';
  if (d === 0) return '⚠️ *VENCE HOY*';
  if (d === 1) return '📌 Vence *mañana*';
  return '📅 Vence en *' + d + ' dias*';
};

const sep = '─'.repeat(36);
const mensajes = [];

// --- Mensaje 1: Encabezado ---
const vencHoy  = [...deudas, ...ordenes].filter(x => x.dias_restantes <= 0).length;
const criticas = [...deudas, ...ordenes].filter(x => x.dias_restantes > 0 && x.dias_restantes <= 3).length;

let header = [
  '📋 *ALERTAS DE VENCIMIENTO*',
  '🗓️ ' + data.generado + '  |  deudas.sekaitech.com.pe',
  sep,
  '📊 *Resumen:*',
  '   • Total alertas: *' + data.total_alertas + '*'
];
if (vencHoy > 0)    header.push('   • 🔴 Vencidas/Hoy: *' + vencHoy + '*');
if (criticas > 0)   header.push('   • 🟠 Criticas (≤3d): *' + criticas + '*');
if (deudas.length)  header.push('   • 💳 Deudas: ' + deudas.length);
if (ordenes.length) header.push('   • 📦 Ordenes: ' + ordenes.length);
mensajes.push(header.join('\n'));

// --- Mensaje 2: Deudas ---
if (deudas.length > 0) {
  let bloque = ['💳 *DEUDAS POR COBRAR (' + deudas.length + ')*', sep];
  deudas.forEach((d, i) => {
    bloque.push('');
    bloque.push(urgIcon(d.dias_restantes) + ' *' + (i + 1) + '. ' + d.cliente + '*');
    bloque.push('   📌 ' + d.descripcion);
    bloque.push('   💰 Pendiente: *' + d.monto + '*');
    bloque.push('   ' + labelDias(d.dias_restantes) + ' (' + d.fecha_vencimiento + ')');
    bloque.push('   👤 Responsable: ' + d.responsable);
  });
  mensajes.push(bloque.join('\n'));
}

// --- Mensaje 3: Ordenes ---
if (ordenes.length > 0) {
  let bloque = ['📦 *ORDENES DE COMPRA (' + ordenes.length + ')*', sep];
  ordenes.forEach((o, i) => {
    bloque.push('');
    bloque.push(urgIcon(o.dias_restantes) + ' *' + (i + 1) + '. OC #' + o.orden_compra + '*');
    bloque.push('   🏢 ' + o.entidad);
    bloque.push('   🔧 ' + o.producto_servicio);
    if (o.empresa_factura) bloque.push('   🧾 Empresa: ' + o.empresa_factura);
    bloque.push('   💰 Monto: *' + o.monto + '*');
    bloque.push('   ' + labelDias(o.dias_restantes) + ' (' + o.fecha_limite_pago + ')');
    bloque.push('   📊 Estado: ' + o.estado_seguimiento);
    bloque.push('   👤 Resp: ' + o.responsable);
  });
  mensajes.push(bloque.join('\n'));
}

return [{ json: { hayAlertas: true, mensajes, total: data.total_alertas } }];

// ENVIAR VIA EVOLUTION API → GRUPO WHATSAPP
